const allowed = ['platform', 'resource', 'record_count_visible', 'status_counts', 'visible_field_names', 'status_code', 'content_type'];
return items.map((item) => {
  let parsed = {};
  const raw = item.json.stdout || item.json.data || item.json;
  if (typeof raw === 'string') {
    try { parsed = JSON.parse(raw); } catch (error) { parsed = { parse_error: String(error) }; }
  } else {
    parsed = raw;
  }
  const out = {};
  for (const key of allowed) {
    if (parsed[key] !== undefined) out[key] = parsed[key];
  }
  out.summary_time_utc = new Date().toISOString();
  out.raw_records_emitted = false;
  out.emailit_writes_attempted = false;
  return { json: out };
});

const lines = ['# Emailit read-only health summary', '', `Generated: ${new Date().toISOString()}`, '', 'Safety: Emailit API v2 GET-only; raw records omitted; no sends/mutations attempted.', ''];
for (const item of items) {
  const j = item.json;
  const status = j.status_code ? `HTTP ${j.status_code}` : 'status unknown';
  const count = j.record_count_visible ?? 'N/A';
  const buckets = j.status_counts && Object.keys(j.status_counts).length ? `; status buckets: ${JSON.stringify(j.status_counts)}` : '';
  lines.push(`- ${j.resource || 'unknown'}: ${status}; visible count ${count}${buckets}`);
}
lines.push('', 'No raw Emailit records, message bodies, recipient addresses, template bodies, webhook URLs, DNS secrets, or API key material emitted.');
return [{ json: { digest_markdown: lines.join('\n'), raw_records_emitted: false, emailit_writes_attempted: false } }];
